    let result: i64 = 1;
    let mut i: i64 = 0;
    while i < n / 2 {
        let left: i64 = vec_get(arr, i);
        let right: i64 = vec_get(arr, n - 1 - i);
        if left != right {
            set result = 0;
            ()
        } else { () };
        set i = i + 1;
        ()
    };
    result
};

